// Filter: CloseDate within current month, not Closed Won/Lost
const now = new Date();
const firstOfMonth = new Date(now.getFullYear(), now.getMonth(), 1);
const lastOfMonth = new Date(now.getFullYear(), now.getMonth() + 1, 0);

const slipped = items.filter(item => {
  const opp = item.json;
  const closeDate = new Date(opp.CloseDate);
  const isThisMonth = closeDate >= firstOfMonth && closeDate <= lastOfMonth;
  const isNotClosed = !['Closed Won', 'Closed Lost'].includes(opp.StageName);
  return isThisMonth && isNotClosed;
});

return slipped.map(item => ({
  json: {
    ...item.json,
    slip_detected: true,
    snapshot_date: now.toISOString()
  }
}));

// Analyze call signals and flag risks
const opp = $input.first().json;
const calls = $input.all().map(i => i.json);

const today = new Date();
const lastDayOfMonth = new Date(today.getFullYear(), today.getMonth() + 1, 0);

// Sort calls by date descending
calls.sort((a, b) => new Date(b.call_date) - new Date(a.call_date));
const lastCall = calls[0];

// Calculate days since last call before month end
const lastCallDate = lastCall ? new Date(lastCall.call_date) : null;
const daysSinceLastCall = lastCallDate 
  ? Math.floor((lastDayOfMonth - lastCallDate) / (1000 * 60 * 60 * 24))
  : 999;

// Build SPICED risk flags
const spicedFlags = [];
if (!opp.EconomicBuyer__c) spicedFlags.push('No Economic Buyer identified');
if (!opp.Champion__c) spicedFlags.push('No Champion identified');
if (!opp.MutualClosePlan__c) spicedFlags.push('No mutual close plan documented');
if (opp.SPICED_CriticalEvent__c && opp.SPICED_CriticalEvent__c.toLowerCase().includes('end of quarter')) {
  spicedFlags.push('Critical Event is vague — end of quarter with no external forcing function');
}
if (opp.SPICED_Impact__c && !opp.SPICED_Impact__c.match(/\$[\d,]+|\d+%|\d+ hours/)) {
  spicedFlags.push('Impact not tied to a quantified business outcome');
}

// Build call risk flags
const callFlags = [];
if (daysSinceLastCall > 14) callFlags.push(`Last call was ${daysSinceLastCall} days before month-end`);
if (lastCall && lastCall.buyer_signals?.hesitation_detected) callFlags.push('Buyer hesitation detected on last call');
if (lastCall && lastCall.buyer_signals?.executive_disengagement) callFlags.push('Executive disengagement detected');
if (lastCall && !lastCall.commitments_followed_up) callFlags.push('Rep commitments from last call not followed up');
if (lastCall && lastCall.buyer_signals?.scope_creep) callFlags.push('Scope creep introduced without pricing resolution');

return [{
  json: {
    ...opp,
    calls: calls,
    last_call_date: lastCallDate ? lastCallDate.toISOString().split('T')[0] : null,
    days_since_last_call: daysSinceLastCall,
    spiced_flags: spicedFlags,
    call_flags: callFlags,
    call_summaries: calls.map(c => `[${c.call_date}] ${c.transcript_summary}`).join('\n\n')
  }
}];

