// Parse Claude response and merge with deal data
const items = $input.all();
const results = [];

for (const item of items) {
  let postmortem;
  try {
    const raw = item.json.text || item.json.content?.[0]?.text || '{}';
    postmortem = JSON.parse(raw.replace(/```json|```/g, '').trim());
  } catch (e) {
    postmortem = { error: 'Failed to parse AI response', raw: item.json };
  }

  // Exclude managed pushes from main report
  if (postmortem.managed_push_flag === true) {
    results.push({ json: { ...item.json, postmortem, is_managed_push: true } });
  } else {
    results.push({ json: { ...item.json, postmortem, is_managed_push: false } });
  }
}

// Sort by ARR descending
results.sort((a, b) => (b.json.Amount || 0) - (a.json.Amount || 0));

return results;

// Build the Slack message from all deal post-mortems
const deals = $('Parse & Sort Results').all();
const calEvent = $('Google Calendar - Find Forecast Meeting').first()?.json;

const trueSlips = deals.filter(d => !d.json.is_managed_push);
const managedPushes = deals.filter(d => d.json.is_managed_push);

const month = new Date().toLocaleString('en-US', { month: 'long', year: 'numeric' });
const meetingDate = calEvent ? new Date(calEvent.start.dateTime).toLocaleString('en-US', {
  weekday: 'long', month: 'long', day: 'numeric', hour: '2-digit', minute: '2-digit'
}) : 'TBD — check calendar';

const totalARR = trueSlips.reduce((sum, d) => sum + (d.json.Amount || 0), 0);

// Build deal blocks
const dealBlocks = trueSlips.map((deal, i) => {
  const d = deal.json;
  const pm = d.postmortem;
  return `*Deal ${i+1}: ${d['Account.Name']} — $${d.Amount?.toLocaleString()} | AE: ${d['Owner.Name']}*
• *Root Cause:* ${pm.root_cause}
• *Risk Rep Missed:* ${pm.risk_rep_missed}
• *Recommended Action:* ${pm.recommended_action}`;
}).join('\n\n---\n\n');

// Team pattern (simplified)
const rootCauses = trueSlips.map(d => d.json.postmortem?.root_cause).filter(Boolean);
const pattern = rootCauses.length > 0 
  ? `${rootCauses.length} of ${trueSlips.length} slips share a common pattern: ${rootCauses[0]}.`
  : 'No clear team-level pattern this month.';

// Managed push note
const managedNote = managedPushes.length > 0
  ? `\n⚠️ *${managedPushes.length} deal(s) excluded as managed push:* ${managedPushes.map(d => d.json['Account.Name']).join(', ')}\n`
  : '';

const message = `📋 *Commit Slip Report — ${month}*
${trueSlips.length} deal(s) committed to close in ${month} did not close. Total ARR at risk: *$${totalARR.toLocaleString()}*
Here's the post-mortem before your *${meetingDate}* forecast meeting.

---

${dealBlocks}

---
${managedNote}
*📊 Team-Level Pattern:*
${pattern}

📅 *Your next forecast leadership meeting: ${meetingDate}. This is ready as a standing agenda item.*`;

return [{ json: { message, deal_count: trueSlips.length, total_arr: totalARR } }];
